import{_ as a,o as d,c as e,a2 as s}from"./chunks/framework.TWA1q3r6.js";const b=JSON.parse('{"title":"🗣️ 1-3Y · 语言爆发期","description":"","frontmatter":{"title":"🗣️ 1-3Y · 语言爆发期"},"headers":[],"relativePath":"stages/1-3y.md","filePath":"stages/1-3y.md"}'),r={name:"stages/1-3y.md"};function o(n,t,i,l,h,c){return d(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="🗣️-1-3y-·-语言爆发期" tabindex="-1">🗣️ 1-3Y · 语言爆发期 <a class="header-anchor" href="#🗣️-1-3y-·-语言爆发期" aria-label="Permalink to &quot;🗣️ 1-3Y · 语言爆发期&quot;">​</a></h1><blockquote><p>从 mama 到&quot;妈妈我不要这个我要那个为什么为什么为什么&quot;。</p><p>语言像瀑布一样涌出来。户外跑跑跑，绘本翻翻翻，泥巴捏捏捏。</p></blockquote><hr><h2 id="🎯-发展里程碑" tabindex="-1">🎯 发展里程碑 <a class="header-anchor" href="#🎯-发展里程碑" aria-label="Permalink to &quot;🎯 发展里程碑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>科学项目</th><th>在做什么</th><th>每天多久</th><th>来源</th></tr></thead><tbody><tr><td>语言</td><td><strong>亲子共读 + 延展对话</strong></td><td>每天15min共读 → 3岁词汇量差3倍</td><td>15-30min/天</td><td>AAP</td></tr><tr><td>大运动</td><td><strong>户外无动力探索</strong></td><td>攀爬/跑/跳 = 前庭+本体感觉自然整合</td><td>每天≥1h户外</td><td>AAP</td></tr><tr><td>精细运动</td><td><strong>涂鸦 / 黏土 / 撕纸</strong></td><td>手指小肌群精细控制 → 为握笔书写做准备</td><td>融入日常玩耍</td><td>—</td></tr><tr><td>社会情感</td><td><strong>情绪命名</strong> Emotion Labeling</td><td>&quot;你现在很生气&quot; → 前额叶调节杏仁核回路建立</td><td>情绪发生时即时</td><td>Lieberman</td></tr><tr><td>自主性</td><td><strong>如厕训练</strong>（18-24M窗口）</td><td>括约肌成熟 + 模仿意愿 = 窗口期</td><td>跟随孩子信号</td><td>AAP</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">科学边界 🔬</p><p>1-3Y是&quot;感统训练&quot;营销重灾区。无医学诊断的感统训练没有RCT支持。真正的感觉统合在户外自由玩耍中就能自然完成 —— 踩水坑、爬土坡、滚草地，比任何课程都有效。</p></div><hr><h2 id="🛡️-装备清单" tabindex="-1">🛡️ 装备清单 <a class="header-anchor" href="#🛡️-装备清单" aria-label="Permalink to &quot;🛡️ 装备清单&quot;">​</a></h2><h3 id="安全必备" tabindex="-1">安全必备 <a class="header-anchor" href="#安全必备" aria-label="Permalink to &quot;安全必备&quot;">​</a></h3><h4 id="🦷-含氟牙膏-儿童牙刷-essential" tabindex="-1">🦷 含氟牙膏 + 儿童牙刷 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🦷-含氟牙膏-儿童牙刷-essential" aria-label="Permalink to &quot;🦷 含氟牙膏 + 儿童牙刷 Essential&quot;">​</a></h4><p>出牙即开始刷，米粒大小含氟牙膏，降低龋齿率。龋齿是可以预防的慢性病。（AAPD）</p><p><strong>选购</strong> 狮王(Lion) / 巧虎 / 舒客宝贝，¥20-50</p><h4 id="☀️-防晒霜-spf30-essential" tabindex="-1">☀️ 防晒霜 SPF30+ <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#☀️-防晒霜-spf30-essential" aria-label="Permalink to &quot;☀️ 防晒霜 SPF30+ Essential&quot;">​</a></h4><p>儿童期紫外线累积与成年黑色素瘤有明确因果链。户外刚需，全年使用。（AAP）</p><p><strong>选购</strong> Thinkbaby / 安热沙儿童版 / Babyganics，¥50-150</p><h4 id="🚲-平衡车-三轮车-头盔-conditional" tabindex="-1">🚲 平衡车 / 三轮车 + 头盔 <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🚲-平衡车-三轮车-头盔-conditional" aria-label="Permalink to &quot;🚲 平衡车 / 三轮车 + 头盔 Conditional&quot;">​</a></h4><p>促进前庭系统和大运动发展。<strong>头盔必配</strong>，从第一次骑就养成习惯。（AAP）</p><p><strong>选购</strong> 平衡车 Strider / KinderKraft ¥300-800 + 头盔 micro/迪卡侬 ¥100-200</p><h3 id="生活装备" tabindex="-1">生活装备 <a class="header-anchor" href="#生活装备" aria-label="Permalink to &quot;生活装备&quot;">​</a></h3><h4 id="🚽-小马桶-如厕训练座-essential" tabindex="-1">🚽 小马桶 / 如厕训练座 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🚽-小马桶-如厕训练座-essential" aria-label="Permalink to &quot;🚽 小马桶 / 如厕训练座 Essential&quot;">​</a></h4><p>18-24个月是如厕训练窗口期。矮小的、脚能着地的小马桶，比大人马桶上的辅助圈好用。</p><p><strong>选购</strong> BabyBjörn / Fisher-Price / 可优比，¥80-300</p><h3 id="认知与情感" tabindex="-1">认知与情感 <a class="header-anchor" href="#认知与情感" aria-label="Permalink to &quot;认知与情感&quot;">​</a></h3><h4 id="📚-绘本-board-books-essential" tabindex="-1">📚 绘本 Board Books <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#📚-绘本-board-books-essential" aria-label="Permalink to &quot;📚 绘本 Board Books Essential&quot;">​</a></h4><p>出生就可以开始亲子共读，每天15分钟效果量巨大。好绘本不贵，图书馆也是好选择。（AAP）</p><p><strong>选购</strong> 图书馆借阅 + 京东/当当自营囤货，¥0-500/年</p><h4 id="🧱-开放式玩具-积木-黏土-画笔-essential" tabindex="-1">🧱 开放式玩具（积木/黏土/画笔） <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🧱-开放式玩具-积木-黏土-画笔-essential" aria-label="Permalink to &quot;🧱 开放式玩具（积木/黏土/画笔） Essential&quot;">​</a></h4><p>发散性思维 + 精细运动，远优于电子声光玩具。（AAP）</p><p><strong>选购</strong></p><table tabindex="0"><thead><tr><th>推荐</th><th>品牌</th><th>亮点</th><th>入手价</th></tr></thead><tbody><tr><td>传世之选</td><td>Grimm&#39;s</td><td>手工椴木 + 无毒水性漆 + 残值70%+ + 用10年</td><td>≤¥800（团购）</td></tr><tr><td>向上兼容</td><td>LEGO DUPLO</td><td>兼容标准LEGO + 残值稳定 + ABS安全标准最严</td><td>≤¥260（拼多多百补）</td></tr><tr><td>环保之选</td><td>Plan Toys</td><td>橡胶木回收料 + B Corp + Red Dot</td><td>—</td></tr><tr><td>国产优选</td><td>木玩世家</td><td>云和产业带龙头（全球60%木玩产自浙江云和）</td><td>Plan Toys 20-30%价格</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">❌ 避坑清单</p><ul><li><strong>早教机/点读笔（高端款）</strong> — 2岁前零屏幕，2-5岁≤1h/天。人际互动效果远大于设备。替代：真人共读</li><li><strong>&quot;右脑开发&quot;闪卡</strong> — &quot;右脑开发&quot;这个概念本身就没有RCT支持。替代：对话 + 绘本</li><li><strong>感统训练课（无诊断）</strong> — 无医学诊断的感统训练无RCT。替代：自由玩耍 + 户外</li></ul></div><hr><h2 id="🌟-1y-成长多巴胺准备金" tabindex="-1">🌟 1Y+ 成长多巴胺准备金 <a class="header-anchor" href="#🌟-1y-成长多巴胺准备金" aria-label="Permalink to &quot;🌟 1Y+ 成长多巴胺准备金&quot;">​</a></h2><blockquote><p>把发育刚需变成亲子好时光。</p></blockquote><table tabindex="0"><thead><tr><th>物品</th><th>为什么值得</th><th>参考方向</th><th>预算</th></tr></thead><tbody><tr><td>🌧️ 儿童雨靴+雨衣</td><td>雨天 = 最佳感官探索，踩水坑是天然感统训练</td><td>Crocs / Petit Bateau</td><td>¥100-300</td></tr><tr><td>🌱 微型园艺工具</td><td>种一棵草莓 = 观察+等待+因果关系的真实课</td><td>Burgon &amp; Ball / 宜家</td><td>¥30-150</td></tr><tr><td>✏️ 可书写墙</td><td>涂鸦是精细运动核心通道，涂鸦墙比画纸自由太多</td><td>3M白板贴 / 黑板漆</td><td>¥100-300</td></tr><tr><td>⛺ 露营入门装备</td><td>3Y+每年4次户外过夜 = 48h无屏幕自然教育</td><td>牧高笛 / 挪客</td><td>¥500-2,000</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">多巴胺准备金的筛选逻辑 💡</p><p>每一项至少满足以下两个条件：<strong>高频使用</strong>（每周≥3次）、<strong>审美溢价合理</strong>（同品类价差50%以内）、<strong>附带发展价值</strong>（服务于户外/精细运动/感官探索）。</p></div>',36)])])}const u=a(r,[["render",o]]);export{b as __pageData,u as default};
